<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &quot;damo-vilab/text-to-video-ms-1.7b&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></span>
